            best_arrival = std::numeric_limits<double>::max();
            best_area_flow = std::numeric_limits<double>::max();
            best_area = std::numeric_limits<float>::max();
            best_size = UINT32_MAX;
            stagnation_count = 0;

            // Dynamically adjust exploration based on problem size
            double exploration_boost = 1.0 + (0.5 * cuts.cuts(index).size() / 10.0);
            temperature = std::max(temperature * exploration_boost, 1000.0);

            // Adaptive cooling adjustment
            cooling_rate = std::max(0.8, cooling_rate * 0.95);  // Maintain minimum cooling rate
